import{_ as e,o as a,c as o,ag as i}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Configurationエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"BashとZsh用のシェルエイリアスで、シェル、Git、SSH、サーバー設定ファイルを即座に開きます。","frontmatter":{"title":"Configurationエイリアス | Dotfiles","description":"BashとZsh用のシェルエイリアスで、シェル、Git、SSH、サーバー設定ファイルを即座に開きます。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Configurationエイリアス preview","canonical":"/ja/aliases/configuration/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Configurationエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"Configurationエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/configuration/","sidebar":true,"meta":[{"name":"keywords","content":"configuration aliases, shell config, dotfiles, bash aliases, zsh aliases, git config, ssh config"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Configurationエイリアス - Dotfiles"},{"name":"twitter:description","content":"シェルエイリアスで、シェル、Git、SSH、サーバー設定ファイルを即座に開きます。"},{"name":"og:title","content":"Configurationエイリアス - Dotfiles"},{"name":"og:description","content":"シェルエイリアスで、シェル、Git、SSH、サーバー設定ファイルを即座に開きます。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/configuration/index.md","filePath":"ja/aliases/configuration/index.md","lastUpdated":1773010926000}'),d={name:"ja/aliases/configuration/index.md"};function r(n,t,s,c,h,l){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="configurationエイリアス" tabindex="-1">Configurationエイリアス <a class="header-anchor" href="#configurationエイリアス" aria-label="Permalink to &quot;Configurationエイリアス&quot;">​</a></h1><p>1つのコマンドでデフォルトエディタで設定ファイルを開きます。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>Configurationエイリアスは、頻繁に編集する設定ファイルを開くためのショートカットを提供します。これらのエイリアスは<code>configuration.aliases.sh</code>で定義され、chezmoiによって自動的にロードされます。</p><p>各エイリアスは、システムのデフォルトテキストエディタで対応するファイルを起動し、ファイルパスを覚えたり長いコマンドを入力する必要がなくなります。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="シェル設定" tabindex="-1">シェル設定 <a class="header-anchor" href="#シェル設定" aria-label="Permalink to &quot;シェル設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>bshrc</code></td><td>Bash設定ファイル（~/.bashrc）を開く</td></tr><tr><td><code>bshp</code></td><td>Bashプロファイル（~/.bash_profile）を開く</td></tr><tr><td><code>zshrc</code></td><td>Zsh設定ファイル（~/.zshrc）を開く</td></tr><tr><td><code>zshp</code></td><td>Zshプロファイル（~/.zprofile）を開く</td></tr></tbody></table><h3 id="バージョン管理" tabindex="-1">バージョン管理 <a class="header-anchor" href="#バージョン管理" aria-label="Permalink to &quot;バージョン管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>gcfg</code></td><td>Git設定ファイル（~/.gitconfig）を開く</td></tr><tr><td><code>gign</code></td><td>Gitignoreファイル（~/.gitignore）を開く</td></tr></tbody></table><h3 id="ネットワークとサーバー" tabindex="-1">ネットワークとサーバー <a class="header-anchor" href="#ネットワークとサーバー" aria-label="Permalink to &quot;ネットワークとサーバー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>apconf</code></td><td>Apache設定ファイルを開く</td></tr><tr><td><code>ngconf</code></td><td>Nginx設定ファイルを開く</td></tr><tr><td><code>sshconf</code></td><td>SSH設定ファイル（~/.ssh/config）を開く</td></tr><tr><td><code>hosts</code></td><td>hostsファイル（/etc/hosts）を開く</td></tr></tbody></table><h3 id="開発ツール" tabindex="-1">開発ツール <a class="header-anchor" href="#開発ツール" aria-label="Permalink to &quot;開発ツール&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>dockcomp</code></td><td>Docker Composeファイルを開く</td></tr><tr><td><code>eddir</code></td><td>現在のディレクトリをデフォルトエディタで開く</td></tr></tbody></table>',14)])])}const u=e(d,[["render",r]]);export{g as __pageData,u as default};
